const output = [];

for (const item of items) {
  const result = item.json.chart.result[0];

  const meta = result.meta;
  const quote = result.indicators.quote[0];

  // 1. Filter out null values to prevent NaN errors in subsequent nodes
  const validCloses = quote.close ? quote.close.filter(c => c !== null) : [];
  const validVolumes = quote.volume ? quote.volume.filter(v => v !== null) : [];

  output.push({
    json: {
      sector: item.json.sector, // <--- MOVED HERE (Correct placement)
      symbol: meta.symbol,
      stock_name: meta.longName,
      current_price: meta.regularMarketPrice,
      previous_close: meta.chartPreviousClose,

      // 2. Dynamically grab from the end of the array using .at()
      day_1_close: validCloses.at(-5) || validCloses.at(0) || 0,
      day_2_close: validCloses.at(-4) || 0,
      day_3_close: validCloses.at(-3) || 0,
      day_4_close: validCloses.at(-2) || 0,
      day_5_close: validCloses.at(-1) || 0, // Latest day

      // 3. Apply dynamic logic for volume and safe average calculation
      latest_volume: validVolumes.at(-1) || 0,
      avg_5d_volume: validVolumes.length > 0 
        ? validVolumes.reduce((a, b) => a + b, 0) / validVolumes.length 
        : 0
    }
  });
}

return output;

const output = [];

for (const item of items) {
  const d1 = item.json.day_1_close; // oldest
  const d3 = item.json.day_3_close;
  const d4 = item.json.day_4_close;
  const d5 = item.json.day_5_close; // latest

  const current = item.json.current_price;
  const prev = item.json.previous_close;

  // Safe return calculation
  const one_day_return = prev
    ? ((current - prev) / prev) * 100
    : 0;

  const three_day_return = d3
    ? ((current - d3) / d3) * 100
    : 0;

  const five_day_return = d1
    ? ((current - d1) / d1) * 100
    : 0;

  const volume_ratio = item.json.avg_5d_volume
    ? item.json.latest_volume / item.json.avg_5d_volume
    : 1;

  let momentum_score =
    (one_day_return * 0.5) +
    (three_day_return * 0.3) +
    (five_day_return * 0.2);

  // Volume boost
  if (volume_ratio > 1.2) {
    momentum_score += 1;
  }

  output.push({
    json: {
      ...item.json,

      one_day_return: Number(one_day_return.toFixed(2)),
      three_day_return: Number(three_day_return.toFixed(2)),
      five_day_return: Number(five_day_return.toFixed(2)),
      volume_ratio: Number(volume_ratio.toFixed(2)),
      momentum_score: Number(momentum_score.toFixed(2))
    }
  });
}

return output;

// We need to map the symbols back to their sectors because 
// the HTTP Request node replaced the Google Sheet data.
const sectorMap = {
  "INFY.NS": "IT",
  "TCS.NS": "IT",
  "WIPRO.NS": "IT",
  "HDFCBANK.NS": "BANK",
  "ICICIBANK.NS": "BANK",
  "SBIN.NS": "BANK",
  "TMPV.NS": "AUTO",
  "MARUTI.NS": "AUTO"
};

// Grouping object to hold sectors
const grouped = {};

// Process all incoming stock items
for (const item of items) {
  const stock = item.json;

  // Look up the sector using the stock symbol, fallback to "UNKNOWN"
  const sector = sectorMap[stock.symbol] || "UNKNOWN";

  if (!grouped[sector]) {
    grouped[sector] = {
      sector: sector,
      total_stocks: 0,
      stocks: []
    };
  }

  // Push the stock into its respective sector group
  grouped[sector].stocks.push(stock);
  grouped[sector].total_stocks += 1;
}

// Return grouped sectors as separate items
return Object.values(grouped).map(group => ({
  json: group
}));

// Split current vs historical data
const currentData = [];
const historicalData = [];

// FIX: Apply IST timezone offset (5 hours 30 minutes) to avoid the UTC morning gap
const offsetMs = 5.5 * 60 * 60 * 1000; 
const localDate = new Date(Date.now() + offsetMs);
const today = localDate.toISOString().split("T")[0];

for (const item of items) {
  const row = item.json;

  if (!row.date && row.sector_strength_score !== undefined) {
    currentData.push(row);
  }

  if (row.date && row.date !== today) {
    historicalData.push(row);
  }
}

// Get latest historical score per sector
const latestHistorical = {};

for (const row of historicalData) {
  const sector = row.sector;
  const date = new Date(row.date);

  if (
    !latestHistorical[sector] ||
    date > new Date(latestHistorical[sector].date)
  ) {
    latestHistorical[sector] = row;
  }
}

// Rotation logic
function getRotationSignal(current, previous) {
  const diff = current - previous;

  if (diff >= 0.5) return "ROTATION_IN";
  if (diff <= -0.5) return "ROTATION_OUT";
  if (current >= 1.5) return "LEADING";
  if (current <= -1) return "LAGGING";
  return "STABLE";
}

// Final output
const output = currentData.map(row => {
  const sector = row.sector;
  const currentScore = Number(row.sector_strength_score);

  const historical = latestHistorical[sector];
  const previousScore = historical
    ? Number(historical.sector_strength_score)
    : null;

  const scoreChange =
    previousScore !== null
      ? +(currentScore - previousScore).toFixed(2)
      : null;

  const rotationSignal =
    previousScore !== null
      ? getRotationSignal(currentScore, previousScore)
      : "NO_HISTORY";

  return {
    json: {
      date: today,
      sector,
      sector_strength_score: currentScore,
      trend: row.trend,
      previous_score: previousScore,
      score_change: scoreChange,
      rotation_signal: rotationSignal
    }
  };
});

return output;

// Grab the original data from before the AI Agent wiped it!
// .all() gets the full array of items, which matches our AI outputs 1:1
const originalItems = $('Prepare AI Insights Prompt').all();

return items.map((item, index) => {
    let parsed = {};

    // Match the current AI output with its original untouched data using the index
    const originalData = originalItems[index].json;

    // 1. Strip markdown formatting before parsing to prevent JSON errors
    try {
        // Grab output, default to empty JSON string if undefined
        let cleanOutput = item.json.output || "{}"; 

        // Remove ```json and ``` tags
        cleanOutput = cleanOutput.replace(/```json/gi, '').replace(/```/g, '').trim();

        parsed = JSON.parse(cleanOutput);
    } catch (err) {
        parsed = {
            insight: "Could not parse AI output",
            reason: "Parse Error: " + err.message, 
            action: "Neutral",
            confidence: "0"
        };
    }

    // 2. We can now safely grab the exact sector and date directly from the ORIGINAL data!
    const sector = originalData.sector || "UNKNOWN";
    const date = originalData.date;

    // Build the formatted insight
    const formattedInsight = `
SECTOR: ${sector}
DATE: ${date}

AI INSIGHT:
${parsed.insight}

REASON:
${parsed.reason}

ACTION:
${parsed.action}

CONFIDENCE:
${parsed.confidence}/10
`.trim();

    // 3. Rebuild the final item. 
    // By using "...originalData", we bring back all the lost data (trend, score, rotation_signal, etc.)
    return {
        json: {
            ...originalData, 
            ai_insight: parsed.insight,
            ai_reason: parsed.reason,
            ai_action: parsed.action,
            ai_confidence: Number(parsed.confidence) || 0,
            formatted_ai_insight: formattedInsight
        }
    };
});

return items.map(item => {
  const row = item.json;

  const prompt = `
You are a professional stock market sector rotation analyst.

Analyze today's sector movement.

Date: ${row.date}
Sector: ${row.sector}
Current Score: ${row.sector_strength_score}
Previous Score: ${row.previous_score}
Score Change: ${row.score_change}
Trend: ${row.trend}
Rotation Signal: ${row.rotation_signal}

Provide:
1. Short institutional insight
2. Possible reason for movement
3. Suggested action (Watchlist / Bullish / Bearish / Neutral)
4. Confidence score out of 10

Keep response concise.
`;

  return {
    json: {
      ...row,
      ai_prompt: prompt
    }
  };
});

// Production-grade sector strength calculation

return items.map(item => {
  const sectorData = item.json;
  const stocks = sectorData.stocks || [];

  if (stocks.length === 0) {
    return {
      json: {
        sector: sectorData.sector,
        error: "No stocks found"
      }
    };
  }

  const avgMomentum =
    stocks.reduce((sum, stock) => sum + (stock.momentum_score || 0), 0) / stocks.length;

  const avgOneDayReturn =
    stocks.reduce((sum, stock) => sum + (stock.one_day_return || 0), 0) / stocks.length;

  const avgThreeDayReturn =
    stocks.reduce((sum, stock) => sum + (stock.three_day_return || 0), 0) / stocks.length;

  const avgVolumeRatio =
    stocks.reduce((sum, stock) => sum + (stock.volume_ratio || 0), 0) / stocks.length;

  // Final strength score formula: Trust the underlying stock momentum
  const sectorStrengthScore = avgMomentum;

  // Sector trend label
  let trend = "Neutral";

  if (sectorStrengthScore >= 2) {
    trend = "Strong Bullish";
  } else if (sectorStrengthScore >= 0.5) {
    trend = "Bullish";
  } else if (sectorStrengthScore <= -2) {
    trend = "Strong Bearish";
  } else if (sectorStrengthScore <= -0.5) {
    trend = "Bearish";
  }

  return {
    json: {
      sector: sectorData.sector,
      total_stocks: stocks.length,
      avg_momentum_score: Number(avgMomentum.toFixed(2)),
      avg_1d_return: Number(avgOneDayReturn.toFixed(2)),
      avg_3d_return: Number(avgThreeDayReturn.toFixed(2)),
      avg_volume_ratio: Number(avgVolumeRatio.toFixed(2)),
      sector_strength_score: Number(sectorStrengthScore.toFixed(2)),
      trend: trend,
      stocks: stocks
    }
  };
});

